where.if:
and (lower(a.title) like #{keyword}
  or lower(a.slug) like #{keyword}
  or lower(a.summary) like #{keyword}
  or lower(a.content_text) like #{keyword})

mapper.select:
select at.article_id, t.id, t.name, '/tag/' || t.slug as url from tags t join article_tags at on at.tag_id = t.id where at.article_id in
#{articleId}
order by at.article_id, t.id
